import json
import os
import uuid
from datetime import datetime, timezone

import boto3
from botocore.exceptions import ClientError

sns = boto3.client("sns")

DEFAULT_SUBJECT = os.getenv("DEFAULT_SUBJECT", "Event Notification")
DEFAULT_NOTIFICATION_TYPE = os.getenv("DEFAULT_NOTIFICATION_TYPE", "generic")


def build_subject(notification_type: str) -> str:
    subjects = {
        "generic": "General Event Notification",
        "alert": "Alert Notification",
        "warning": "Warning Notification",
        "info": "Information Notification",
        "success": "Success Notification",
        "failure": "Failure Notification",
    }
    return subjects.get(notification_type, DEFAULT_SUBJECT)


def build_message_payload(event: dict, notification_type: str, message_content):
    payload = {
        "id": event.get("id", str(uuid.uuid4())),
        "type": notification_type,
        "timestamp": event.get("timestamp", datetime.now(timezone.utc).isoformat()),
        "source": event.get("source", "lambda.event.notification.system"),
        "message": message_content,
        "metadata": event.get("metadata", {}),
    }

    if notification_type == "alert":
        payload["severity"] = event.get("severity", "high")
    elif notification_type == "warning":
        payload["severity"] = event.get("severity", "medium")
    elif notification_type == "info":
        payload["severity"] = event.get("severity", "low")
    elif notification_type == "success":
        payload["status"] = "success"
    elif notification_type == "failure":
        payload["status"] = "failure"
        payload["error_code"] = event.get("error_code")

    return payload


def publish_to_sns(topic_arn: str, message_payload: dict, subject: str, message_attributes: dict = None):
    publish_args = {
        "TopicArn": topic_arn,
        "Message": json.dumps(message_payload),
        "Subject": subject[:100],
    }

    if message_attributes:
        publish_args["MessageAttributes"] = message_attributes

    return sns.publish(**publish_args)


def build_message_attributes(notification_type: str, event: dict):
    attributes = {
        "notification_type": {
            "DataType": "String",
            "StringValue": notification_type,
        }
    }

    if "severity" in event:
        attributes["severity"] = {
            "DataType": "String",
            "StringValue": str(event["severity"]),
        }

    if "source" in event:
        attributes["source"] = {
            "DataType": "String",
            "StringValue": str(event["source"]),
        }

    return attributes


def parse_event(event: dict):
    topic_arn = event.get("topic_arn") or event.get("TopicArn")
    message_content = event.get("message") or event.get("message_content") or event.get("body")
    notification_type = event.get("notification_type", DEFAULT_NOTIFICATION_TYPE)
    subject = event.get("subject") or build_subject(notification_type)

    if not topic_arn:
        raise ValueError("Missing required field: topic_arn")
    if message_content is None:
        raise ValueError("Missing required field: message")

    return topic_arn, message_content, notification_type, subject


def lambda_handler(event, context):
    try:
        topic_arn, message_content, notification_type, subject = parse_event(event)
        message_payload = build_message_payload(event, notification_type, message_content)
        message_attributes = build_message_attributes(notification_type, event)

        response = publish_to_sns(
            topic_arn=topic_arn,
            message_payload=message_payload,
            subject=subject,
            message_attributes=message_attributes,
        )

        return {
            "statusCode": 200,
            "body": json.dumps(
                {
                    "success": True,
                    "message_id": response.get("MessageId"),
                    "topic_arn": topic_arn,
                    "notification_type": notification_type,
                }
            ),
        }

    except ValueError as e:
        return {
            "statusCode": 400,
            "body": json.dumps(
                {
                    "success": False,
                    "error": str(e),
                }
            ),
        }
    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "success": False,
                    "error": e.response.get("Error", {}).get("Message", str(e)),
                }
            ),
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "success": False,
                    "error": str(e),
                }
            ),
        }